from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent description from one or more astronaut‑related triples."""
    if not triples:
        return ""
    parts: list[str] = []
    for t in triples:
        s, p, o = t.subject, t.predicate, t.object
        # Basic natural‑language mappings for common astronaut predicates
        if p == "birthDate":
            parts.append(f"{s} was born on {o}")
        elif p == "birthPlace":
            parts.append(f"{s} was born in {o}")
        elif p == "nationality":
            parts.append(f"{s} is a {o} astronaut")
        elif p == "mission":
            parts.append(f"{s} flew on {o}")
        elif p == "timeInSpace":
            try:
                minutes = float(o)
                parts.append(f"{s} spent {minutes:.0f} minutes in space")
            except ValueError:
                parts.append(f"{s} spent {o} in space")
        elif p == "occupation":
            parts.append(f"{s} worked as a {o}")
        elif p == "status":
            parts.append(f"{s} is {o.lower()}")
        elif p == "deathDate":
            parts.append(f"{s} died on {o}")
        elif p == "deathPlace":
            parts.append(f"{s} died in {o}")
        elif p in {"award", "awards", "ribbonAward"}:
            parts.append(f"{s} received the {o} award")
        elif p == "selectedByNasa":
            parts.append(f"{s} was selected by NASA in {o}")
        elif p == "title":
            parts.append(f"{s} held the title of {o}")
        elif p == "commander":
            parts.append(f"{s} was the commander of {o}")
        elif p == "backupPilot":
            parts.append(f"{s} served as backup pilot for {o}")
        elif p == "crewMembers":
            parts.append(f"{s} had crew member {o}")
        elif p == "operator":
            parts.append(f"{s} was operated by {o}")
        else:
            # Fallback generic phrasing
            parts.append(f"{s} {p} {o}")
    # Join clauses into a single coherent sentence
    sentence = "; ".join(parts) + "."
    # Ensure sentence starts with a capital letter
    return sentence[0].upper() + sentence[1:]

# EVOLVE-BLOCK-END

